targets.rawSql:
SELECT count() AS hours_recorded_today
FROM default.hourly_last_72h_sums
WHERE toDate(hour_bucket) = today();

SELECT avg(wattage_winrates) AS today_winrate
FROM default.hourly_last_72h_sums
WHERE toDate(hour_bucket) = toDate(now());

SELECT avg(wattage_winrates) AS last_24h_wattage_winrate
FROM default.hourly_last_72h_sums
WHERE hour_bucket >= toStartOfHour(now() - INTERVAL 24 HOUR);

SELECT avg(wattage_winrates) AS last_72h_wattage_winrate
FROM default.hourly_last_72h_sums
WHERE hour_bucket >= toStartOfHour(now() - INTERVAL 72 HOUR);

SELECT SUM(wattage_Requests) AS Requests
FROM default.hourly_last_72h_sums
WHERE toDate(hour_bucket) = toDate(now());

SELECT sum(wattage_Requests) AS Requests
FROM default.hourly_last_72h_sums
WHERE toDate(hour_bucket) = toDate(now() - INTERVAL 1 DAY);

SELECT sum(wattage_Requests) AS last_24h_all_requests
FROM default.hourly_last_72h_sums
WHERE hour_bucket >= now() - INTERVAL 24 HOUR;

SELECT sum(wattage_Requests) AS last_72h_all_requests
FROM default.hourly_last_72h_sums
WHERE hour_bucket >= now() - INTERVAL 72 HOUR;

SELECT sum(wattage_Impressions) AS impressions
FROM default.hourly_last_72h_sums
WHERE toDate(hour_bucket) = toDate(now() - INTERVAL 1 DAY);

SELECT sum(wattage_Impressions) AS last_24h_wattage_impressions
FROM default.hourly_last_72h_sums
WHERE hour_bucket >= toStartOfHour(now() - INTERVAL 24 HOUR);

SELECT sum(wattage_Impressions) AS last_72h_wattage_impressions
FROM default.hourly_last_72h_sums
WHERE hour_bucket >= toStartOfHour(now() - INTERVAL 72 HOUR);
